  	const int n, const int ky, bool use_10000=true, bool use_5000=true) 

{

    //

    if(n == 0 && ky == 0) {

        return {0, 0, 0};

    }

    if(ky == 0) {

        return {-1, -1, -1};

    }

    if(ky == n) {

        return {0, 0, n};

    }



