    inline void build(const std::vector<T>& arr) noexcept {
        size_ = 1;
        while (size_ < static_cast<int>(arr.size())) size_ <<= 1;
        std::copy(arr.begin(), arr.end(), &data_[size_-1]);
        std::fill(&data_[size_ + arr.size()-1], &data_[2*size_-1], identity_);
        for (int k = size_ - 2; k >= 0; --k)
            data_[k] = op_(data_[2*k+1], data_[2*k+2]);
    }

    inline void set(int idx, T val) noexcept {
        idx += size_ - 1;
        data_[idx] = val;
        while (idx > 0) {
            idx = (idx - 1) / 2;
            data_[idx] = op_(data_[2*idx+1], data_[2*idx+2]);
